                coordonnees = input("\nCoordonnées (x y) : ").split()
                if len(coordonnees) != 2:
                    print("Format invalide. Utilisez 'x y'")
                    continue

                x, y = int(coordonnees[0]), int(coordonnees[1])
                resultat = self.tirer(x, y)
